const botaoAlternarSenha=document.querySelector("#botao-alternar-senha");botaoAlternarSenha.addEventListener("click",(e)=>{const iconeALternarSenha=e.currentTarget.querySelector(".bi");senha.type=senha.type==="password"?"text":"password";iconeALternarSenha.classList.toggle("bi-eye");iconeALternarSenha.classList.toggle("bi-eye-slash")})